    add $05                           ; advance to next 5-byte entry
    ld l, a
    ld a, h
    adc $00
    ld h, a
    jr .scan
.done:
    ret                               ; back to bank $16 plus-clamp ($4710)

; Port of LoadBrd_471c ($471C): match one 5-byte entry against the parents.
.checkentry:
