    cp [hl]
    jr z, .e2
    ld a, [$da73]                     ; parent 1 family code
    cp [hl]
    jr nz, .edone
.e2:
    inc hl
    ld a, [$da70]                     ; parent 2 species (specific)
    cp [hl]
    jr z, .e3
    ld a, [$da74]                     ; parent 2 family code
    cp [hl]
    jr nz, .edone
.e3:
    inc hl
    ld a, [$da77]                     ; offspring plus value
    cp [hl]
    jr c, .edone                      ; plus < threshold -> skip
